mapper.select:
SELECT COUNT(*)
FROM product_currencies
WHERE product_no = #{productNo}
  AND currency_code = #{currencyCode}

SELECT COUNT(*)
FROM product_rates
WHERE product_no = #{productNo}
  AND rate_no = #{rateNo}
  AND period_month = #{periodMonth}

SELECT COUNT(*)
FROM product_subscriptions
WHERE user_no = #{userNo}
  AND product_no = #{productNo}
  AND subscription_status NOT IN ('해지', '만기', '취소')

SELECT MAX(subscribed_dt)
FROM product_subscriptions
WHERE user_no = #{userNo}

mapper.update:
UPDATE foreign_account_balances fab
SET fab.balance = fab.balance - #{amount},
    fab.updated_dt = SYSDATE
WHERE fab.currency_code = #{currencyCode}
  AND fab.balance >= #{amount}
  AND fab.fx_acnt_id = (
      SELECT fa.fx_acnt_no
      FROM foreign_accounts fa
      WHERE fa.account_no = #{accountNo}
        AND fa.user_no = #{userNo}
        AND fa.account_no LIKE '333-02-%'
  )

mapper.select:
SELECT COUNT(*)
FROM id_verifications
WHERE verification_no = #{verificationNo}
  AND user_no = #{userNo}
  AND product_no = #{productNo}
  AND verification_status = '성공'
  AND matched_name_yn = 'Y'
  AND matched_birth_yn = 'Y'
  AND (expired_dt IS NULL OR expired_dt > SYSDATE)

mapper.update:
UPDATE coupon
SET is_used = 'Y',
    used_dt = SYSDATE
WHERE coupon_no = #{couponNo}
  AND user_no = #{userNo}
  AND is_used = 'N'
